import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import org.junit.jupiter.api.Test

internal class IndentationRuleIssueReproTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Issue repro try-catch indent`() {
        val code =
            """
            fun test() = try {
              1
            }
            catch(_: Throwable) {
              2
            }
            """.trimIndent()
        // The issue is that ktlint 0.48.2+ wants to indent 'catch'
        indentationRuleAssertThat(code)
            .withEditorConfigValue("indent_size", "2")
            .hasNoLintViolations()
    }

    @Test
    fun `Issue repro typealias indent`() {
        val code =
            """
            typealias Foo =
              HashMap<Bar, Baz?>
            """.trimIndent()
        // The issue is that ktlint 0.48.2+ wants to unindent 'HashMap'
        indentationRuleAssertThat(code)
            .withEditorConfigValue("indent_size", "2")
            .hasNoLintViolations()
    }
}
"}

